using System.Linq.Expressions;
using Gehtsoft.ExpressionToJs;

Expression<Func<int, bool>> rule = x => x > 0 &amp;&amp; x < 100;

// Program.cs - the stub is constant, so this response is highly cacheable
app.MapGet("/js/expr-stub.js", () =>
    Results.Text(ExpressionToJsStubAccessor.GetJsIncludesAsString(), "application/javascript"));

// stub.js already loaded once on the page
var x = 42;
var ok = ((jsv_greater(x, 0)) &amp;&amp; (jsv_less(x, 100)));   // true

// GET /js/rules/{name} -> a script defining a function called {name}
app.MapGet("/js/rules/{name}", (string name) =>
{
    string expr = new ExpressionCompiler(Rules.For(name)).JavaScriptExpression;
    string script = $"function {name}(x) {{ return {expr}; }}";
    return Results.Text(script, "application/javascript");
});

static string CompileRule(LambdaExpression rule)
{
    var compiler = new ExpressionCompiler(rule);
    compiler.Parameters.MapReference(_ => true);   // turn the reference() convention on for all
    return compiler.JavaScriptExpression;
}
 
// m => m.Password == m.Confirm
//   -> jsv_equal(reference('Password'), reference('Confirm'))

// GET /js/rules/{name} -> defines a function {name}() that calls reference()
app.MapGet("/js/rules/{name}", (string name) =>
{
    string expr = CompileRule(Rules.For(name));
    string script = $"function {name}() {{ return {expr}; }}";
    return Results.Text(script, "application/javascript");
});

compiler.Methods.MapMethod(typeof(AccountRules), nameof(AccountRules.IsStrong),
                           "jsv_account_strong($0)");
compiler.Parameters.MapReference(_ => true);
 
Expression<Func<Account, bool>> rule =
    m => AccountRules.IsStrong(m) &amp;&amp; m.Password == m.Confirm;
 
// ((jsv_account_strong(reference())) &amp;&amp; (jsv_equal(reference('Password'), reference('Confirm'))))
//                      ^ whole model                  ^ a field

compiler.Parameters.Map(
    _ => true,
    p => $"reference('{p.Type.Name}')",
    (e, p) => $"reference('{p.Type.Name}', '{ExpressionCompiler.ParameterAccessPath(e)}')");
 
// m => m.Password == m.Confirm
//   -> jsv_equal(reference('Account', 'Password'), reference('Account', 'Confirm'))

function reference(type, path) {
    return document.forms[type].elements[path].value;
}

compiler.Parameters.Map(
    _ => true,
    p => "value",
    (e, p) => "value." + ExpressionCompiler.ParameterAccessPath(e));
 
// m => m.Password == m.Confirm
//   -> jsv_equal(value.Password, value.Confirm)

@* AgeRule is the C# lambda x => x > 0 &amp;&amp; x < 100 *@
<asp:TextBox id="Age" runat="server" />
<asp:CustomValidator runat="server" ControlToValidate="Age"
     ClientValidationFunction="validateAge" ErrorMessage="Enter a value between 1 and 99." />
 
<script>
    function ageOk(x) { return @Html.Raw(new ExpressionCompiler(AgeRule).JavaScriptExpression); }
 
    function validateAge(sender, args) {
        args.IsValid = ageOk(args.Value);
    }
</script>

$.validator.addMethod("ageOk", function (value, element) {
    return this.optional(element) || ageOk(value);
}, "Enter a value between 1 and 99.");
 
$("#signup").validate({
    rules: { age: { ageOk: true } }
});

// single field
function ageOkValidator(control) {
    return ageOk(control.value) ? null : { ageOk: true };
}
 
// whole model - compiled for object access, fed the form's value
function passwordsMatchValidator(group) {
    return rule(group.value) ? null : { passwordsMatch: true };
}
 
this.form = new FormGroup({
    password: new FormControl(""),
    confirm:  new FormControl(""),
}, { validators: passwordsMatchValidator });

const [age, setAge] = useState("");
const valid = ageOk(age);
 
return (
    <>
        <input value={age} onChange={e => setAge(e.target.value)} />
        {!valid &amp;&amp; <span className="error">Enter a value between 1 and 99.</span>}
    </>
);

const age = ref("");
const ageValid = computed(() => ageOk(age.value));
 
// whole model - pass the reactive state object (compiled for object access)
const formValid = computed(() => rule(form));

var compiler = new ExpressionCompiler(rule, DateTimeMode.Utc);
// or: compiler.DateMode = DateTimeMode.Utc;  (before reading JavaScriptExpression)
string js = compiler.JavaScriptExpression;

class Order
{
    public string      CouponCode { get; set; }
    public DateTime    PlacedOn   { get; set; }
    public OrderStatus Status     { get; set; }   // enum { Pending, Shipped, Delivered }
}

public static class Coupon
{
    public static bool IsValid(string code) =>
        code != null &amp;&amp; Regex.IsMatch(code, "^[A-Z]{4}-\\d{4}$");
}

var compiler = new ExpressionCompiler(rule);
compiler.Methods.MapMethod(typeof(Coupon), nameof(Coupon.IsValid), "jsv_coupon_ok($0)");
 
// o => Coupon.IsValid(o.CouponCode)
//   -> jsv_coupon_ok(o.CouponCode)

function jsv_coupon_ok(code) {
    return code != null &amp;&amp; /^[A-Z]{4}-\d{4}$/.test(code);
}

compiler.Members.MapMember(typeof(DateTime), nameof(DateTime.DayOfYear), "jsv_dayofyear($obj)");
 
// o => o.PlacedOn.DayOfYear <= 31
//   -> jsv_lessorequal(jsv_dayofyear(o.PlacedOn), 31)

function jsv_dayofyear(d) {
    var start = new Date(d.getFullYear(), 0, 0);
    return Math.floor((d - start) / 86400000);
}

compiler.Methods.MapMethod(typeof(OrderRules), nameof(OrderRules.StatusIs), "jsv_status_is($0, $1)");
compiler.Constants.MapConstant<OrderStatus>(s => "'" + s + "'");
 
// o => OrderRules.StatusIs(o.Status, OrderStatus.Shipped)
//   default       -> jsv_status_is(o.Status, 1)
//   with the map  -> jsv_status_is(o.Status, 'Shipped')

sealed class CouponTranslator : IMethodCallTranslator
{
    public bool TryTranslate(MethodCallExpression call, IExpressionEmitContext ctx, out string js)
    {
        if (call.Method.DeclaringType == typeof(Coupon) &amp;&amp; call.Method.Name == "IsValid"
            &amp;&amp; call.Arguments.Count == 2)
        {
            string code = ctx.Emit(call.Arguments[0]);
            bool strict = (bool)((ConstantExpression)call.Arguments[1]).Value;
            js = strict ? $"jsv_coupon_strict({code})" : $"jsv_coupon_ok({code})";
            return true;
        }
        js = null;
        return false;   // not mine - let another translator or the built-ins handle it
    }
}
 
compiler.Methods.AddTranslator(new CouponTranslator());
 
// o => Coupon.IsValid(o.CouponCode, true)
//   -> jsv_coupon_strict(o.CouponCode)

using Jint;
using Gehtsoft.ExpressionToJs;
 
static void AssertRule<T>(Expression<Func<T, bool>> rule, T input)
{
    // 1. server side: compile and invoke the delegate
    bool expected = rule.Compile()(input);
 
    // 2. emit the JavaScript
    string js = new ExpressionCompiler(rule).JavaScriptExpression;
 
    // 3. run it in Jint with the stub loaded and the parameter bound
    var engine = new Engine();
    engine.Execute(ExpressionToJsStubAccessor.GetJsIncludesAsString());
    engine.SetValue(rule.Parameters[0].Name, input);
    bool actual = engine.Evaluate(js).AsBoolean();
 
    // 4. same verdict on both tiers?
    Assert.Equal(expected, actual);
}

// a range check, at the boundary
AssertRule<int>(age => age >= 18 &amp;&amp; age <= 120, 18);
 
// "required" - tabs and other whitespace must fail, as in C#
AssertRule<string>(s => !string.IsNullOrWhiteSpace(s), "\t");
 
// integer division: C# says 11 / 2 == 5; the stub keeps JS agreeing
AssertRule<int>(n => n / 2 == 5, 11);

